import requests
import os


class Tools:
    @staticmethod
    def run(endpoint: str, params: dict = None) -> dict:
        """
        Calls OpenAlex API.
        Examples:
        - endpoint: "works?search=diffusion models"
        - endpoint: "works/W1234567890"
        - endpoint: "authors/A123456789"
        - endpoint: "institutions/I123456789"
        """
        api_key = os.environ.get("OPENALEX_API_KEY")
        base_url = "https://api.openalex.org"

        headers = {
            "User-Agent": "YourApp (mailto:your@email.com)",
            "Accept": "application/json",
        }
        if api_key:
            headers["x-api-key"] = api_key

        url = f"{base_url}/{endpoint.lstrip('/')}"

        if params is None:
            params = {}

        try:
            r = requests.get(url, headers=headers, params=params, timeout=15)
            r.raise_for_status()
            return r.json()
        except Exception as e:
            return {"error": str(e)}
